// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title BatchTypes
 * @notice Shared data types used across all OriginPharm contracts.
 *         Import this file into any contract that needs access to these structs/enums.
 */

/// @notice Represents the current stage of a batch in the supply chain
enum BatchStatus {
    Produced,    // Minted by manufacturer; not yet released
    Released,    // Released to distributor
    InTransit,   // Being shipped between stakeholders
    Received,    // Received at pharmacy/hospital
    Dispensed    // Distributed to a patient (end of lifecycle)
}

/// @notice Core data stored for each pharmaceutical batch
struct BatchData {
    uint256 tokenId;          // Unique batch identifier
    string  medicineName;     // e.g. "Amoxicillin 500mg"
    string  batchNumber;      // Manufacturer's internal batch ref
    uint256 manufactureDate;  // Unix timestamp
    uint256 expiryDate;       // Unix timestamp
    address manufacturer;     // Address of the minting manufacturer
    BatchStatus status;       // Current supply chain status
}

/// @notice A single entry in the custody history of a batch
struct CustodyRecord {
    address from;       // Sender address (zero for initial mint)
    address to;         // Receiver address
    BatchStatus status; // Status at the time of this transfer
    uint256 timestamp;  // Unix timestamp of the event
    string  notes;      // Optional notes (e.g. shipment ID, carrier)
}

contracts/MintContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./BatchTypes.sol";

/**
 * @title MintContract
 * @notice Handles minting of pharmaceutical batch tokens.
 *         Only authorised manufacturers may mint new batches.
 *
 * @dev This is a simplified token registry (not a full ERC-721).
 *      Each batch gets a unique tokenId incremented from 1.
 *      The ControlContract reads from this contract to validate batches.
 */
contract MintContract {

    // ─── State ────────────────────────────────────────────────────────────────

    /// @notice Contract owner — set in constructor, used to authorise manufacturers
    address public owner;

    /// @notice Auto-incrementing ID counter for batch tokens
    uint256 private _nextTokenId;

    /// @notice Maps tokenId → BatchData
    mapping(uint256 => BatchData) private _batches;

    /// @notice Tracks which addresses are authorised manufacturers
    mapping(address => bool) public authorisedManufacturers;

    // ─── Events ───────────────────────────────────────────────────────────────

    event ManufacturerAuthorised(address indexed manufacturer);
    event ManufacturerRevoked(address indexed manufacturer);
    event BatchMinted(
        uint256 indexed tokenId,
        address indexed manufacturer,
        string medicineName,
        string batchNumber,
        uint256 expiryDate
    );

    // ─── Modifiers ────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "MintContract: caller is not owner");
        _;
    }

    modifier onlyManufacturer() {
        require(
            authorisedManufacturers[msg.sender],
            "MintContract: caller is not an authorised manufacturer"
        );
        _;
    }

    // ─── Constructor ──────────────────────────────────────────────────────────

    constructor() {
        owner = msg.sender;
        _nextTokenId = 1; // Token IDs start at 1
    }

    // ─── Owner Functions ──────────────────────────────────────────────────────

    /**
     * @notice Grants manufacturer role to an address.
     * @param manufacturer Address to authorise.
     */
    function authoriseManufacturer(address manufacturer) external onlyOwner {
        // TODO: add input validation (e.g. non-zero address check)
        authorisedManufacturers[manufacturer] = true;
        emit ManufacturerAuthorised(manufacturer);
    }

    /**
     * @notice Revokes manufacturer role from an address.
     * @param manufacturer Address to revoke.
     */
    function revokeManufacturer(address manufacturer) external onlyOwner {
        // TODO: check manufacturer is currently authorised before revoking
        authorisedManufacturers[manufacturer] = false;
        emit ManufacturerRevoked(manufacturer);
    }

    // ─── Manufacturer Functions ───────────────────────────────────────────────

    /**
     * @notice Mints a new batch token representing a pharmaceutical product batch.
     * @param medicineName  Human-readable name of the medicine.
     * @param batchNumber   Manufacturer's internal batch reference.
     * @param expiryDate    Unix timestamp of the batch expiry date.
     * @return tokenId      The ID assigned to the newly minted batch.
     *
     * @dev TODO: Add validation:
     *      - expiryDate must be in the future
     *      - medicineName and batchNumber must not be empty strings
     *      - Consider emitting a QR-code-friendly hash of the tokenId
     */
    function mintBatch(
        string calldata medicineName,
        string calldata batchNumber,
        uint256 expiryDate
    ) external onlyManufacturer returns (uint256 tokenId) {
        tokenId = _nextTokenId++;

        _batches[tokenId] = BatchData({
            tokenId:         tokenId,
            medicineName:    medicineName,
            batchNumber:     batchNumber,
            manufactureDate: block.timestamp,
            expiryDate:      expiryDate,
            manufacturer:    msg.sender,
            status:          BatchStatus.Produced
        });

        emit BatchMinted(tokenId, msg.sender, medicineName, batchNumber, expiryDate);
    }

    // ─── Read Functions ───────────────────────────────────────────────────────

    /**
     * @notice Returns the full BatchData struct for a given tokenId.
     * @param tokenId The batch token to look up.
     */
    function getBatch(uint256 tokenId) external view returns (BatchData memory) {
        // TODO: revert with a descriptive error if tokenId does not exist
        return _batches[tokenId];
    }

    /**
     * @notice Returns true if a tokenId has been minted (exists in the registry).
     * @param tokenId The batch token to check.
     */
    function batchExists(uint256 tokenId) external view returns (bool) {
        return _batches[tokenId].manufacturer != address(0);
    }

    /**
     * @notice Allows the ControlContract to update the status of a batch.
     * @param tokenId   The batch to update.
     * @param newStatus The new BatchStatus value.
     *
     * @dev TODO: Restrict this so only the ControlContract address can call it.
     *      One approach: store the ControlContract address in state and add a modifier.
     */
    function updateStatus(uint256 tokenId, BatchStatus newStatus) external {
        // TODO: access control — only ControlContract should be able to call this
        _batches[tokenId].status = newStatus;
    }
}

contracts/ControlContract.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./BatchTypes.sol";
import "./MintContract.sol";

/**
 * @title ControlContract
 * @notice Manages the internal supply chain pipeline for pharmaceutical batches.
 *         Handles custody transfers: Manufacturer → Distributor → Pharmacy/Hospital.
 *
 * Permitted actions per role:
 *   Manufacturer  → release()
 *   Distributor   → shipment()
 *   Pharmacy      → receipt()
 *
 * @dev Each state-changing function:
 *      1. Validates the caller's role
 *      2. Validates the batch is in the correct preceding state
 *      3. Updates the batch status via MintContract
 *      4. Appends a CustodyRecord to the batch history
 *      5. Emits an event
 */
contract ControlContract {

    // ─── State ────────────────────────────────────────────────────────────────

    /// @notice Reference to the MintContract for batch lookups and status updates
    MintContract public mintContract;

    /// @notice Contract owner — manages role assignments
    address public owner;

    /// @notice Role mappings
    mapping(address => bool) public authorisedDistributors;
    mapping(address => bool) public authorisedPharmacies;

    /// @notice Maps tokenId → ordered list of custody records
    mapping(uint256 => CustodyRecord[]) private _custodyHistory;

    /// @notice Maps tokenId → current custodian address
    mapping(uint256 => address) public currentCustodian;

    // ─── Events ───────────────────────────────────────────────────────────────

    event BatchReleased(uint256 indexed tokenId, address indexed manufacturer, address indexed distributor, uint256 timestamp);
    event BatchShipped(uint256 indexed tokenId, address indexed distributor, address indexed recipient, string notes, uint256 timestamp);
    event BatchReceived(uint256 indexed tokenId, address indexed receiver, uint256 timestamp);

    // ─── Modifiers ────────────────────────────────────────────────────────────

    modifier onlyOwner() {
        require(msg.sender == owner, "ControlContract: caller is not owner");
        _;
    }

    modifier onlyAuthorisedManufacturer() {
        require(
            mintContract.authorisedManufacturers(msg.sender),
            "ControlContract: caller is not an authorised manufacturer"
        );
        _;
    }

    modifier onlyDistributor() {
        require(
            authorisedDistributors[msg.sender],
            "ControlContract: caller is not an authorised distributor"
        );
        _;
    }

    modifier onlyPharmacy() {
        require(
            authorisedPharmacies[msg.sender],
            "ControlContract: caller is not an authorised pharmacy/hospital"
        );
        _;
    }

    // ─── Constructor ──────────────────────────────────────────────────────────

    /**
     * @param mintContractAddress The deployed address of the MintContract.
     */
    constructor(address mintContractAddress) {
        owner = msg.sender;
        mintContract = MintContract(mintContractAddress);
    }

    // ─── Role Management ──────────────────────────────────────────────────────

    function authoriseDistributor(address distributor) external onlyOwner {
        // TODO: non-zero address check
        authorisedDistributors[distributor] = true;
    }

    function revokeDistributor(address distributor) external onlyOwner {
        authorisedDistributors[distributor] = false;
    }

    function authorisePharmacy(address pharmacy) external onlyOwner {
        // TODO: non-zero address check
        authorisedPharmacies[pharmacy] = true;
    }

    function revokePharmacy(address pharmacy) external onlyOwner {
        authorisedPharmacies[pharmacy] = false;
    }

    // ─── Supply Chain Functions ───────────────────────────────────────────────

    /**
     * @notice Step 1 — Manufacturer releases a produced batch to a distributor.
     * @param tokenId     The batch token being released.
     * @param distributor The distributor address receiving the batch.
     *
     * @dev Preconditions:
     *      - Batch must exist and have status Produced
     *      - msg.sender must be the original manufacturer of the batch
     *      - distributor must be an authorised distributor
     *
     * TODO: Validate that distributor address is authorised before proceeding.
     * TODO: Validate that msg.sender matches batch.manufacturer (not just any manufacturer).
     */
    function release(uint256 tokenId, address distributor)
        external
        onlyAuthorisedManufacturer
    {
        BatchData memory batch = mintContract.getBatch(tokenId);

        require(
            batch.status == BatchStatus.Produced,
            "ControlContract: batch must be in Produced state to release"
        );

        mintContract.updateStatus(tokenId, BatchStatus.Released);

        _appendCustody(tokenId, msg.sender, distributor, BatchStatus.Released, "");
        currentCustodian[tokenId] = distributor;

        emit BatchReleased(tokenId, msg.sender, distributor, block.timestamp);
    }

    /**
     * @notice Step 2 — Distributor records a shipment event.
     * @param tokenId   The batch token being shipped.
     * @param recipient The address of the pharmacy or hospital receiving the batch.
     * @param notes     Optional shipment notes (e.g. carrier ID, temperature log reference).
     *
     * TODO: Enforce that msg.sender == currentCustodian[tokenId].
     * TODO: Consider allowing multi-hop shipments (InTransit → InTransit).
     */
    function shipment(uint256 tokenId, address recipient, string calldata notes)
        external
        onlyDistributor
    {
        BatchData memory batch = mintContract.getBatch(tokenId);

        require(
            batch.status == BatchStatus.Released || batch.status == BatchStatus.InTransit,
            "ControlContract: batch must be Released or InTransit to ship"
        );

        mintContract.updateStatus(tokenId, BatchStatus.InTransit);

        _appendCustody(tokenId, msg.sender, recipient, BatchStatus.InTransit, notes);
        currentCustodian[tokenId] = recipient;

        emit BatchShipped(tokenId, msg.sender, recipient, notes, block.timestamp);
    }

    /**
     * @notice Step 3 — Pharmacy or hospital confirms receipt of a batch.
     * @param tokenId The batch token being received.
     *
     * TODO: Enforce that msg.sender == currentCustodian[tokenId].
     */
    function receipt(uint256 tokenId)
        external
        onlyPharmacy
    {
        BatchData memory batch = mintContract.getBatch(tokenId);

        require(
            batch.status == BatchStatus.InTransit,
            "ControlContract: batch must be InTransit to confirm receipt"
        );

        mintContract.updateStatus(tokenId, BatchStatus.Received);

        _appendCustody(tokenId, currentCustodian[tokenId], msg.sender, BatchStatus.Received, "");
        currentCustodian[tokenId] = msg.sender;

        emit BatchReceived(tokenId, msg.sender, block.timestamp);
    }

    // ─── Internal Helpers ─────────────────────────────────────────────────────

    function _appendCustody(
        uint256 tokenId,
        address from,
        address to,
        BatchStatus status,
        string memory notes
    ) internal {
        _custodyHistory[tokenId].push(CustodyRecord({
            from:      from,
            to:        to,
            status:    status,
            timestamp: block.timestamp,
            notes:     notes
        }));
    }

    // ─── Read Functions ───────────────────────────────────────────────────────

    /**
     * @notice Returns the full custody history array for a batch.
     * @param tokenId The batch to query.
     */
    function getCustodyHistory(uint256 tokenId)
        external
        view
        returns (CustodyRecord[] memory)
    {
        return _custodyHistory[tokenId];
    }
}
